function cleanDdgUrl(url: string): string {
  try {
    if (url.startsWith("//")) {
      url = "https:" + url;
    }
    const parsed = new URL(url);
    const uddg = parsed.searchParams.get("uddg");
    if (uddg) {
      return decodeURIComponent(uddg);
    }
  } catch (e) {
    // Ignore URL parse errors
  }
  return url;
}

